import React from 'react';
import './empresasPanel.css';

const empresas = [
  {
    nombre: "Empresa A",
    descripcion: "Descripción corta de la empresa A",
    imagen: "/ruta/logo1.png"
  },
  {
    nombre: "Empresa B",
    descripcion: "Descripción corta de la empresa B",
    imagen: "/ruta/logo2.png"
  },
  {
    nombre: "Empresa C",
    descripcion: "Descripción corta de la empresa C",
    imagen: "/ruta/logo3.png"
  },
  {
    nombre: "Empresa D",
    descripcion: "Descripción corta de la empresa D",
    imagen: "/ruta/logo4.png"
  }
];

const EmpresasPanel = () => {
  return (
    <div className="empresas-panel">
      <h2 className="empresas-titulo">Empresas</h2>
      <div className="empresas-grid">
        {empresas.map((empresa, index) => (
          <div key={index} className="empresa-card">
            <img src={empresa.imagen} alt={empresa.nombre} className="empresa-imagen" />
            <h3 className="empresa-nombre">{empresa.nombre}</h3>
            <p className="empresa-descripcion">{empresa.descripcion}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default EmpresasPanel;
